import React, { useEffect, useMemo, useState, useCallback } from 'react';
import { useTable } from 'react-table';
import AddLaborHours from './AddLaborHours.js';

const LaborHours = ({ apiBaseUrl }) => {
  const [employees, setEmployees] = useState([]);

  const fetchAPI = useCallback(async (url, options = {}) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        'Authorization': `Bearer ${authToken}`,
        'Content-Type': 'application/json',
      },
    });
    if (!response.ok) {
      const errorResponse = await response.json();
      throw new Error(errorResponse.message || `Error fetching ${url}`);
    }
    return response.json();
  }, []);

  useEffect(() => {
    const fetchEmployees = async () => {
      try {
        const data = await fetchAPI(`${apiBaseUrl}/employeesAPI`);
        setEmployees(data);
      } catch (error) {
        console.error('Failed to fetch employees:', error);
      }
    };

    fetchEmployees();
  }, [fetchAPI, apiBaseUrl]);

  const data = useMemo(() => employees.map(employee => ({
    empid: employee.empid,
    name: `${employee.name} ${employee.surname}`.trim(), // Combining name and surname, trimming if surname is empty
    department: employee.department,
    tel: employee.tel,
    mail: employee.mail,
    wage: employee.wage,
  })), [employees]);

  const columns = useMemo(() => [
    {
      Header: 'Employee ID',
      accessor: 'empid',
    },
    {
      Header: 'Name',
      accessor: 'name',
    },
    {
      Header: 'Department',
      accessor: 'department',
    },
    {
      Header: 'Telephone',
      accessor: 'tel',
    },
    {
      Header: 'Email',
      accessor: 'mail',
    },
    {
      Header: 'Wage',
      accessor: 'wage',
    },
  ], []);

  const tableInstance = useTable({ columns, data });

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
  } = tableInstance;

  return (
    <div>
        <h1>Labor Hours</h1>
            <AddLaborHour apiBaseUrl={apiBaseUrl} />
      <table {...getTableProps()} style={{ border: 'solid 1px blue', width: '100%' }}>
        <thead>
          {headerGroups.map(headerGroup => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map(column => (
                <th {...column.getHeaderProps()} style={{ borderBottom: 'solid 3px red', background: 'aliceblue', color: 'black', fontWeight: 'bold', padding: '10px' }}>
                  {column.render('Header')}
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map(cell => (
                  <td {...cell.getCellProps()} style={{ padding: '10px', border: 'solid 1px gray' }}>
                    {cell.render('Cell')}
                  </td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

export default LaborHours;
